head.b:skin:
/* SmartLifeLab - Custom Theme */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: 'Noto Sans KR', sans-serif; background: #F9FAFB; color: #1F2937; font-size: 16px; line-height: 1.8; }
a { color: #2563EB; text-decoration: none; }
a:hover { color: #1D4ED8; }
img { max-width: 100%; }

/* Header */
#header-wrap { background: #fff; border-bottom: 2px solid #2563EB; position: sticky; top: 0; z-index: 999; }
#header-inner { max-width: 1100px; margin: 0 auto; padding: 0 20px; height: 60px; display: flex; align-items: center; justify-content: space-between; }
#header-inner h1 a { font-size: 20px; font-weight: 700; color: #2563EB; }
#nav ul { list-style: none; display: flex; gap: 24px; }
#nav ul li a { font-size: 14px; font-weight: 500; color: #374151; }
#nav ul li a:hover { color: #2563EB; }

/* Layout */
#outer-wrapper { max-width: 1100px; margin: 30px auto; padding: 0 20px; display: flex; gap: 28px; }
#main-wrapper { flex: 1; min-width: 0; }
#sidebar-wrapper { width: 300px; flex-shrink: 0; }

/* Post */
.post { background: #fff; border-radius: 10px; padding: 28px; margin-bottom: 24px; box-shadow: 0 1px 4px rgba(0,0,0,0.07); }
.post-title { font-size: 22px; font-weight: 700; margin-bottom: 10px; }
.post-title a { color: #111827; }
.post-title a:hover { color: #2563EB; }
.post-header { margin-bottom: 16px; }
.post-header .date-header { font-size: 13px; color: #9CA3AF; margin-bottom: 6px; }
.post-labels a { display: inline-block; background: #EFF6FF; color: #2563EB; font-size: 12px; padding: 2px 10px; border-radius: 20px; margin-right: 4px; }
.post-body { font-size: 15px; line-height: 1.9; }
.post-body h2 { font-size: 20px; font-weight: 700; margin: 28px 0 12px; border-left: 4px solid #2563EB; padding-left: 10px; }
.post-body h3 { font-size: 17px; font-weight: 600; margin: 22px 0 10px; }
.post-body p { margin-bottom: 16px; }
.post-body ul, .post-body ol { margin: 0 0 16px 24px; }
.post-body table { width: 100%; border-collapse: collapse; margin-bottom: 16px; font-size: 14px; }
.post-body th { background: #2563EB; color: #fff; padding: 8px 12px; text-align: left; }
.post-body td { padding: 8px 12px; border-bottom: 1px solid #E5E7EB; }
.post-body tr:nth-child(even) td { background: #F9FAFB; }
.post-body hr { border: none; border-top: 1px solid #E5E7EB; margin: 28px 0; }
.post-body img { border-radius: 8px; margin: 12px 0; }
.post-footer { margin-top: 20px; font-size: 13px; color: #9CA3AF; }

/* Pager */
#blog-pager { display: flex; justify-content: space-between; padding: 12px 0; }
#blog-pager a { background: #fff; border: 1px solid #E5E7EB; padding: 8px 18px; border-radius: 6px; font-size: 14px; color: #374151; }
#blog-pager a:hover { background: #2563EB; color: #fff; border-color: #2563EB; }

/* Sidebar */
.sidebar-section { background: #fff; border-radius: 10px; padding: 20px; margin-bottom: 20px; box-shadow: 0 1px 4px rgba(0,0,0,0.07); }
.sidebar-section h2 { font-size: 14px; font-weight: 700; color: #111827; margin-bottom: 14px; padding-bottom: 10px; border-bottom: 2px solid #2563EB; }
.sidebar-section ul { list-style: none; }
.sidebar-section ul li { padding: 7px 0; border-bottom: 1px solid #F3F4F6; font-size: 13px; }
.sidebar-section ul li:last-child { border-bottom: none; }
.sidebar-section ul li a { color: #374151; }
.sidebar-section ul li a:hover { color: #2563EB; }

/* Footer */
#footer-wrap { background: #1F2937; color: #9CA3AF; margin-top: 40px; }
#footer-inner { max-width: 1100px; margin: 0 auto; padding: 24px 20px; display: flex; justify-content: space-between; align-items: center; font-size: 13px; }
#footer-inner a { color: #9CA3AF; margin-left: 16px; }
#footer-inner a:hover { color: #fff; }

/* Responsive */
@media(max-width: 768px) {
  #outer-wrapper { flex-direction: column; }
  #sidebar-wrapper { width: 100%; }
  #nav ul { gap: 14px; }
  #header-inner h1 a { font-size: 17px; }
}
